#include <stdio.h>
#include <stdbool.h>

#define DIFS 50      // DCF Interframe Space (μs)
#define RTS_CTS 14  // RTS/CTS exchange time
#define ACK 14      // ACK transmission time
#define SLOT 9      // Slot time (μs)

typedef enum {IDLE, DIFS_WAIT, RTS_SENT, CTS_WAIT, DATA_SEND, ACK_WAIT} state_t;

bool csma_ca_transmit(unsigned char *data, int data_len) {
    state_t current_state = IDLE;
    int backoff_slots;
    int cw = 15;  // Contention window (default)

    // Step 1: Check if channel is idle
    while (channel_sense() != IDLE) {
        wait_channel_idle();
    }

    // Step 2: Wait DIFS
    delay_us(DIFS);

    // Step 3: Generate random backoff
    backoff_slots = random() % (cw + 1);
    delay_us(backoff_slots * SLOT);

    // Step 4: Send RTS (Request to Send)
    send_frame(RTS, destination_addr);
    current_state = RTS_SENT;

    // Step 5: Wait for CTS
    if (wait_for_cts(RTS_CTS_TIMEOUT)) {
        // Step 6: Received CTS, send data
        send_frame(DATA, data, data_len);
        current_state = DATA_SEND;

        // Step 7: Wait for ACK
        if (wait_for_ack(ACK_TIMEOUT)) {
            printf("Transmission successful\\n");
            return true;
        }
    }

    // Collision or no CTS - increase CW and retry
    cw = min((cw + 1) * 2, 1023);
    printf("RTS/CTS failed, doubling CW to %d\\n", cw);

    return false;
}

int main() {
    unsigned char data[] = "Hello, World!";
    bool success = csma_ca_transmit(data, sizeof(data));
    return success ? 0 : 1;
}
